import{_ as r}from"./nyalra_kb-7135827b.js";import{_ as c}from"./nyalra_no_mono-8344e451.js";import{_ as s,W as p,X as i,Y as _,Z as e,$ as a,a1 as t,a2 as m,a0 as d,C as o}from"./framework-91490e6a.js";const f={},g=e("figure",null,[e("img",{src:r,alt:"",tabindex:"0",loading:"lazy"}),e("figcaption")],-1),b={href:"https://tree-novel.com/works/episode/336c2a741e3861e7384cb1a96984fcd9.html",target:"_blank",rel:"noopener noreferrer"},h=e("p",null,"这是在互联网中栖息的不可思议生物·Nyalra于深夜写下的有关互联网、独居生活以及除此之外的事物的图文随笔。",-1),k=d('<hr><p>说起来，这个连载的标题是「奈亚拉面壁自语」，就像在深夜，我独自一人面对墙壁，将我的思绪冷静地转化成文字一样。虽然我并没有特别偏离这一主题，但确认一下自己开始时的心情是很重要的。不管怎么说，这个连载已经持续了半年多了（好厉害！）。</p><p>可喜可贺的是，我的作品『NEEDY GIRL OVERDOSE』已经达到了100万的销量。我要感谢许多人。顺便一提，除此之外，我还写了一本以NGO（主播女孩重度依赖）的世界观为基础的小说，这本小说的编辑是负责这个专栏的编辑。他不仅每周阅读我的奇怪专栏，还校对了接近10万字的我的废话，我真不知道该如何感谢他。</p><p>与这些背后的故事无关，也许有人认为，「已经达到了100万销量，所以应该感觉超级开心吧！？」但实际上......我仍然独自一人坐在电脑前，并不觉得有什么特别。</p><p>并不是在说谎。因为事实如此。没有家人为我庆祝，朋友们也不在乎我的创作（这实际上是一种解脱），一直与我合作的工作人员住在不同的地方。不会有什么「百万祝宴！」的聚会机会。即使在达到100万销量时，也首先是通过Discord联系，当然，那时我也是在家里躺着，也不能与他人分享，只是一个人对着手机说「这样啊」而已。我的世界就是这样的。</p><p>所以，老实说，我还没有太多成就感，因为当达到100万这个数字时，并没有发生什么特别的变化，而最可能为我高兴的粉丝们的表现，我也只能透过显示器看到。制作人说：「将来，制作过百万销量的游戏的事实将成为我的名片。」当热潮过去，当我逐渐成为过去时，人们可能会在某个时刻问：「这家伙是谁？」然后我可以震惊他们地说：「以前的我很厉害！」这么说似乎有点小家子气...</p><p>所以，我将在悠闲的退休生活中享受着，同时有资格自居为一位老年强人，可以对年轻的创作者说：「哎呀，大家都好厉害啊。其实我以前也做过一点游戏哦。」 这个想法令人高兴。我获得了「虽然属性高但升级困难的特立独行老年单位角色」的位置。嗯，希望未来的我能一如既往地保持活力，这才是最好的事情。</p><p>不过，无论如何，在未来的一些喜庆时刻，是否会有某人陪伴在身边一同欢庆呢？这样的时刻是否能够洒脱地庆祝，不必成为专栏的素材，而是能够热闹非凡地度过呢。不过，不管怎么说，从性格上来说，热闹对我来说可能有点难以实现...即使参加某种聚会，也只能想象到自己站在一边，叉着手臂，皱眉看着墙壁，嘟哝着：「嗯...真吵闹啊。」</p><hr><p><img src="'+c+'" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/a564f333f22cafe1aca40d81b0bdcb17.jpg" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/adfdd070ea2e3ac3e810efcb37cad0c8.jpg" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/60a7aa4bf2f5c2433dab4b4376b3ba05.jpg" alt="" loading="lazy"></p><blockquote><p>本周的にゃるら的物品：</p><p>【别西卜兽的手办】这是出自小中千昭的杰作「数码宝贝拓荒者」中的别西卜兽的手办。和玛丽莲·曼森一样，是我童年时期的英雄。后来，奥特曼贝利亚也成为我心目中的英雄之一。我喜欢黑色和紫色！</p></blockquote>',11);function u(y,x){const l=o("ExternalLinkIcon"),n=o("RouterLink");return p(),i("div",null,[_(" more "),g,e("p",null,[a("原文链接："),e("a",b,[a("第38回／100万本でも独り"),t(l)])]),e("blockquote",null,[h,e("p",null,[t(n,{to:"/posts/Translate/nyalra_kb_37.html"},{default:m(()=>[a("【奈亚拉面壁自语】第37回｜奈亚拉体验过的兼职合集【230801】")]),_:1})])]),k])}const V=s(f,[["render",u],["__file","nyalra_kb_38.html.vue"]]);export{V as default};
